pragma cashscript ^0.11.5;

/**
 * A contract which will hold the user's accummulated promo points in the form of tokens.
 *
 * Params:
 *  - adminPubKey: public key of an admin account
 *  - userPubKey: public key of the user generated from wallet mnemonic (address 0/0)
 *  - tokenCategory: promo token category
 *  - byte promo: 1-byte promo type
 *     - 0x01 - up | user points     | user rewards
 *     - 0x02 - rp | referral points | refer-a-friend promo
 *     - 0x03 - lp | loyalty points  | loyalty promo
 *     - 0x04 - cp | champion points | champion promo
 *     - 0x05 - mp | merchant points | ppr promo
 */
contract PromoContract(pubkey adminPubKey, pubkey userPubKey, bytes32 tokenCategory, byte promo) {
    /**
     * Send promo tokens to RewardsSwapContract address for swapping to LIFT tokens.
     *
     * Params:
     *  - userSig: signature of the user's wallet
     *  - targetPromo: current active promo
     *  - rewardsSwapScriptHash: 32-byte script hash of RewardsSwapContract bytecode
     */
    // The reason rewardsSwapScriptHash is a parameter in this covenant instead of
    // a contract parameter is so that the versioning of this contract will not be
    // dependent on RewardsSwapContract; this contract can maintain its current
    // version even if the the swap contract is updated, thus avoiding unnecessary
    // and frequent transfers to new contract versions.
    function send(sig userSig, byte targetPromo, bytes32 rewardsSwapScriptHash) {
        // Ensure that only the user can withdraw tokens
        require(checkSig(userSig, userPubKey), "Only the user can withdraw from the contract");

        // Ensure that target promo is correct
        require(targetPromo == promo, "Target promo is incorrect");

        // Ensure inputs length is at least 1
        require(tx.inputs.length >= 1, "Length of inputs is not within the expected range");

        // Bind input to contract itself (prevents "decoy inputs[0]").
        bytes32 selfScriptHash = hash256(this.activeBytecode);
        bytes35 swapLock = new LockingBytecodeP2SH32(selfScriptHash);
        require(tx.inputs[0].lockingBytecode == swapLock, "inputs[0] must be this contract's UTXO");

        // Ensure at least 3 outputs are present to prevent leakage
        // 1 for tokens to be sent, 2 optional bch and token change outputs
        require(within(tx.outputs.length, 1, 4), "Length of outputs is not within the expected range");

        // Ensure outputs[0] holds the tokens to send
        bool hasDust0th = tx.outputs[0].value <= 1000;
        bool hasTokens0th = tx.outputs[0].tokenAmount > 0;
        bool isCorrectId0th = tx.outputs[0].tokenCategory == tokenCategory;
        require(hasDust0th && hasTokens0th && isCorrectId0th, "Expected token not found on outputs[0]");

        // Ensure that outputs[0] is sent to the rewards swap contract address
        bytes35 rewardsSwapLock = new LockingBytecodeP2SH32(rewardsSwapScriptHash);
        require(tx.outputs[0].lockingBytecode == rewardsSwapLock, "outputs[0] has the wrong receiver");

        // If existing, ensure outputs[1] holds the change bch to be sent back to the contract
        if(tx.outputs.length == 2 || tx.outputs.length == 3) {
            bool hasBch1st = tx.outputs[1].value > 0;
            bool hasNoToken1st = tx.outputs[1].tokenAmount == 0;
            bool hasNoCategory1st = tx.outputs[1].tokenCategory == 0x;
            require(hasBch1st && hasNoToken1st && hasNoCategory1st, "Either no BCH or a token is found in outputs[1]");
            require(tx.outputs[1].lockingBytecode == swapLock, "outputs[1] has the wrong receiver");
        }

        // If existing, ensure outputs[2] holds the change token to be sent back to the contract
        if (tx.outputs.length == 3) {
            bool hasDust2nd = tx.outputs[2].value <= 1000;
            bool hasTokens2nd = tx.outputs[2].tokenAmount > 0;
            bool isCorrectId2nd = tx.outputs[2].tokenCategory == tokenCategory;
            require(hasDust2nd && hasTokens2nd && isCorrectId2nd, "Expected token not found on outputs[2]");
            require(tx.outputs[2].lockingBytecode == swapLock, "outputs[2] has the wrong receiver");
        }
    }

    /**
     * Drain funds if user is inactive for a certain period.
     * An off-chain check is done first to check if the user is inactive for 6 months
     * (time since they last visited the Rewards app). Then an on-chain check is done
     * to check the sequence number of the UTXO the contract has received recently
     * (this is done in case the contract is still receiving UTXOs despite the user
     * being inactive) if it has exceeded at least 6 months.
     *
     * Params:
     *  - adminSig: signature of the admin's wallet
     *  - targetPromo: current active promo
     *  - medianTime: bch blockchain median time fetched from Watchtower
     */
    function drain(sig adminSig, byte targetPromo, int medianTime) {
        // Ensure that only the admin can drain the contract
        require(checkSig(adminSig, adminPubKey), "Only the admin can drain the contract");

        // Ensure that target promo is correct
        require(targetPromo == promo, "Target promo is incorrect");

        // Ensure that the sequence number from inputs[0] is using block height based locktime
        int seqNum0th = tx.inputs[0].sequenceNumber;
        require(seqNum0th <= 500000000, "Sequence number must be height-based");

        // Ensure sequence number of inputs[0] if 6 months have passed (in block height)
        int constant BLOCKS_PER_YEAR = 52560;
        int constant BLOCKS_IN_HALF_YEAR = BLOCKS_PER_YEAR / 2;
        require(seqNum0th >= (medianTime + BLOCKS_IN_HALF_YEAR), "Latest UTXO sequence number is still within timeframe");

        // Ensure 2 outputs are present to prevent leakage
        require(within(tx.outputs.length, 1, 3), "Length of outputs is not the same as expected");

        // Ensure inputs length is at least 1
        require(tx.inputs.length >= 1, "Length of inputs is not within the expected range");

        // Bind input to contract itself (prevents "decoy inputs[0]").
        bytes32 selfScriptHash = hash256(this.activeBytecode);
        bytes35 swapLock = new LockingBytecodeP2SH32(selfScriptHash);
        require(tx.inputs[0].lockingBytecode == swapLock, "inputs[0] must be this contract's UTXO");

        // Ensure outputs[0] holds the total tokens
        bool hasDust0th = tx.outputs[0].value <= 1000;
        bool hasTokens0th = tx.outputs[0].tokenAmount > 0;
        bool isCorrectId0th = tx.outputs[0].tokenCategory == tokenCategory;
        require(hasDust0th && hasTokens0th && isCorrectId0th, "Expected token not found on outputs[0]");

        // Ensure outputs[1] holds the extra bch from inputs' dust and/or extra bch
        bool hasBch1st = tx.outputs[1].value > 0;
        bool hasNoToken1st = tx.outputs[1].tokenAmount == 0;
        bool hasNoCategory1st = tx.outputs[1].tokenCategory == 0x;
        require(hasBch1st && hasNoToken1st && hasNoCategory1st, "Either no BCH or a token is found in outputs[1]");

        // Ensure both outputs are sent to the admin's address
        bytes20 adminPkh = hash160(adminPubKey);
        bytes25 adminLockingBytecode = new LockingBytecodeP2PKH(adminPkh);
        bool correctReceiver0th = tx.outputs[0].lockingBytecode == adminLockingBytecode;
        bool correctReceiver1st = tx.outputs[1].lockingBytecode == adminLockingBytecode;
        require(correctReceiver0th && correctReceiver1st, "Only the admin can receive the funds");
    }

    /**
     * Transfer all assets (BCH and promo tokens) to new PromoContract version.
     *
     * Params:
     *  - adminSig: signature of the admin's wallet
     *  - targetPromo: current active promo
     *  - newContractScriptHash: 32-byte script hash of new PromoContract version bytecode
     */
    function transferToNewVersion(sig adminSig, byte targetPromo, bytes32 newContractScriptHash) {
        // Ensure that only the admin can transfer assets to the new contract version
        require(checkSig(adminSig, adminPubKey), "Only the admin can drain the contract");

        // Ensure that target promo is correct
        require(targetPromo == promo, "Target promo is incorrect");

        // Ensure inputs length is at least 1
        require(tx.inputs.length >= 1, "Length of inputs is not within the expected range");

        // Bind input to contract itself (prevents "decoy inputs[0]").
        bytes32 selfScriptHash = hash256(this.activeBytecode);
        bytes35 swapLock = new LockingBytecodeP2SH32(selfScriptHash);
        require(tx.inputs[0].lockingBytecode == swapLock, "inputs[0] must be this contract's UTXO");

        // Ensure 2 outputs are present to prevent leakage
        require(tx.outputs.length == 2, "Length of outputs is not the same as expected");

        // Ensure outputs[0] holds the total tokens
        bool hasDust0th = tx.outputs[0].value <= 1000;
        bool hasTokens0th = tx.outputs[0].tokenAmount > 0;
        bool isCorrectId0th = tx.outputs[0].tokenCategory == tokenCategory;
        require(hasDust0th && hasTokens0th && isCorrectId0th, "Expected token not found on outputs[0]");

        // Ensure outputs[1] holds the extra bch from inputs' dust and/or extra bch
        bool hasBch1st = tx.outputs[1].value > 0;
        bool hasNoToken1st = tx.outputs[1].tokenAmount == 0;
        bool hasNoCategory1st = tx.outputs[1].tokenCategory == 0x;
        require(hasBch1st && hasNoToken1st && hasNoCategory1st, "Either no BCH or a token is found in outputs[1]");

        // Ensure both outputs are sent to the new contract address
        bytes35 newContractLock = new LockingBytecodeP2SH32(newContractScriptHash);
        require(tx.outputs[0].lockingBytecode == newContractLock, "outputs[0] has incorrect locking bytecode");
        require(tx.outputs[1].lockingBytecode == newContractLock, "outputs[1] has incorrect locking bytecode");
    }

    // remove before this is pushed to production
    // same covenant as withdraw but with less rules
    // meant for easy withdrawal of funds during development period
    function easyWithdraw(sig userSig, byte targetPromo) {
        // Ensure that only the user can withdraw tokens
        require(checkSig(userSig, userPubKey), "Only the user can withdraw their tokens");

        // Ensure that target promo is correct
        require(targetPromo == promo, "Target promo is incorrect");
    }
}
